<?php namespace App\Http\Controllers\Expense; use App\Http\Controllers\Controller; use App\Models\ExpenseCategory; use Illuminate\Http\Request; use Illuminate\Validation\Rule;
class ExpenseCategoryController extends Controller {public function index(Request $r){return $this->respond(ExpenseCategory::when($r->boolean('active_only'),fn($q)=>$q->where('is_active',true))->orderBy('sort_order')->orderBy('name')->get());} public function store(Request $r){return $this->respond(ExpenseCategory::create($this->data($r)), 'Expense category created.',true,201);} public function update(Request $r,ExpenseCategory $expenseCategory){$expenseCategory->update($this->data($r,$expenseCategory));return $this->respond($expenseCategory,'Expense category updated.');} public function destroy(ExpenseCategory $expenseCategory){if($expenseCategory->expenses()->exists())return $this->respondError('Referenced categories cannot be deleted; deactivate it instead.',422);$expenseCategory->delete();return $this->respond(null,'Expense category deleted.');} private function data(Request $r,?ExpenseCategory $c=null){return $r->validate(['name'=>['required','string','max:100',Rule::unique('expense_categories','name')->ignore($c?->id)],'description'=>['nullable','string'],'sort_order'=>['nullable','integer','min:0'],'is_active'=>['sometimes','boolean']]);}}
